import React, { useState, useRef } from 'react';
import { Link } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { Search, ShoppingCart, Menu } from 'lucide-react';

const Navbar = () => {
  const [isSearchActive, setIsSearchActive] = useState(false);
  const searchInputRef = useRef(null);

  const cartItems = useSelector((state) => state.cart?.items || []);
  const cartCount = cartItems.reduce((total, item) => total + item.quantity, 0);

  const handleSearchClick = (e) => {
    if (!isSearchActive) {
      e.preventDefault();
      setIsSearchActive(true);
      setTimeout(() => {
        searchInputRef.current?.focus();
      }, 300);
    }
  };

  return (
    <header className="w-full bg-white shadow-sm sticky top-0 z-50">
      <div className="container mx-auto px-4 py-3">
        <div className="flex items-center justify-between">

          {/* Mobile Menu Icon */}
          <button className="md:hidden p-1">
            <Menu size={24} />
          </button>

          {/* Logo & Brand Name */}
          <Link to="/" className="flex items-center gap-2">
            <img
              src="https://i.postimg.cc/NMXqNBzW/5f3ee798-2700-4e54-a412-96ef2d12dc1a.png"
              alt="Videm's Gallery Logo"
              className="hidden md:block h-8 w-auto object-contain"
            />
            <h1 className="text-xl font-bold tracking-tight text-gray-900">
              Videm's <span className="text-orange-500">Gallery</span>
            </h1>
          </Link>

          {/* Expanding Search Bar (Animation Restored) */}
          <div className="flex items-center gap-4">
            <div
              className={`flex items-center transition-all duration-300 ease-in-out overflow-hidden ${isSearchActive ? 'w-48 md:w-80' : 'w-8'
                }`}
            >
              <input
                ref={searchInputRef}
                type="text"
                placeholder="Search..."
                className={`flex-1 h-9 px-3 border border-gray-200 rounded-l-md outline-none transition-opacity duration-300 ${isSearchActive ? 'opacity-100' : 'opacity-0'
                  }`}
                onBlur={() => setIsSearchActive(false)}
              />
              <button
                onClick={handleSearchClick}
                className="h-9 w-9 flex items-center justify-center bg-orange-500 text-white rounded-r-md flex-shrink-0"
                aria-label="Search"
              >
                <Search size={20} />
              </button>
            </div>

            <Link to="/cart" className="relative p-1 text-gray-700">
              <ShoppingCart size={24} />
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-orange-500 text-white text-[10px] font-bold h-4 w-4 rounded-full flex items-center justify-center">
                  {cartCount}
                </span>
              )}
            </Link>
          </div>
        </div>
      </div>

      {/* Desktop Navigation Links */}
      <div className="hidden md:block w-full border-t border-gray-100 bg-white">
        <div className="container mx-auto px-4 py-3">
          <ul className="flex items-center justify-center space-x-12">
            {['LIVING ROOM', 'BEDROOM', 'DINING', 'STUDY'].map((category) => (
              <li key={category}>
                <Link to={`/products?category=${category.toLowerCase().replace(' ', '-')}`} className="text-sm font-bold text-gray-800 hover:text-orange-500 tracking-wide transition-colors">
                  {category}
                </Link>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </header>
  );
};

export default Navbar;
